    acc_in_data_x : in data port AHRS::Data_Types::FLOAT32_TYPE_AADL;
    acc_in_data_y : in data port AHRS::Data_Types::FLOAT32_TYPE_AADL;
    acc_in_data_z : in data port AHRS::Data_Types::FLOAT32_TYPE_AADL;

