    ACC_PC1 : parameter accelero_sub.acc_out_data_x -> acc_out_data_x;
    ACC_PC2 : parameter accelero_sub.acc_out_data_y -> acc_out_data_y;
    ACC_PC3 : parameter accelero_sub.acc_out_data_z -> acc_out_data_z;

  end ACCELERO.IMPL;

